mapper.select:
SELECT g.guest_id, g.name, g.gender, g.id_card, g.phone, g.room_id, r.room_number, g.status, g.guest_type, g.check_in_date, g.pre_leave_date FROM guest g LEFT JOIN room r ON g.room_id = r.room_id WHERE 1=1
AND g.status = #{status}
AND ( g.name LIKE CONCAT('%', #{keyword}, '%') OR g.id_card LIKE CONCAT('%', #{keyword}, '%') OR g.phone LIKE CONCAT('%', #{keyword}, '%') OR r.room_number LIKE CONCAT('%', #{keyword}, '%') )
AND g.room_id = #{roomId}
AND g.guest_type = #{guestType}
AND g.group_id = #{groupId}
ORDER BY g.check_in_date DESC
